/**
 * Bootstrap 5.3.0 - Essential JavaScript
 * Minimal implementation for basic functionality
 */

// Bootstrap Modal
window.bootstrap = {
    Modal: function(element, options) {
        this.element = element;
        this.options = options || {};
        this.init();
    },
    init: function() {
        // Basic modal functionality
        if (this.element) {
            this.element.style.display = 'none';
        }
    },
    show: function() {
        if (this.element) {
            this.element.style.display = 'block';
            this.element.classList.add('show');
        }
    },
    hide: function() {
        if (this.element) {
            this.element.style.display = 'none';
            this.element.classList.remove('show');
        }
    }
};

// Initialize modals
document.addEventListener('DOMContentLoaded', function() {
    const modalTriggers = document.querySelectorAll('[data-bs-toggle="modal"]');
    modalTriggers.forEach(function(trigger) {
        trigger.addEventListener('click', function(e) {
            e.preventDefault();
            const targetId = this.getAttribute('data-bs-target');
            const target = document.querySelector(targetId);
            if (target) {
                const modal = new bootstrap.Modal(target);
                modal.show();
            }
        });
    });

    // Close modals
    const closeButtons = document.querySelectorAll('[data-bs-dismiss="modal"], .modal .btn-close');
    closeButtons.forEach(function(button) {
        button.addEventListener('click', function() {
            const modal = this.closest('.modal');
            if (modal) {
                modal.style.display = 'none';
                modal.classList.remove('show');
            }
        });
    });
});

// Dropdown functionality
document.addEventListener('click', function(e) {
    const dropdowns = document.querySelectorAll('.dropdown-menu.show');
    dropdowns.forEach(function(dropdown) {
        dropdown.classList.remove('show');
    });

    const dropdownToggle = e.target.closest('[data-bs-toggle="dropdown"]');
    if (dropdownToggle) {
        e.preventDefault();
        const dropdownMenu = dropdownToggle.nextElementSibling;
        if (dropdownMenu && dropdownMenu.classList.contains('dropdown-menu')) {
            dropdownMenu.classList.toggle('show');
        }
    }
});

// Alert dismiss functionality
document.addEventListener('DOMContentLoaded', function() {
    const dismissButtons = document.querySelectorAll('[data-bs-dismiss="alert"]');
    dismissButtons.forEach(function(button) {
        button.addEventListener('click', function() {
            const alert = this.closest('.alert');
            if (alert) {
                alert.style.display = 'none';
            }
        });
    });
});

// Collapse functionality
document.addEventListener('click', function(e) {
    const collapseToggle = e.target.closest('[data-bs-toggle="collapse"]');
    if (collapseToggle) {
        e.preventDefault();
        const targetId = collapseToggle.getAttribute('data-bs-target') || collapseToggle.getAttribute('href');
        const target = document.querySelector(targetId);
        if (target) {
            target.classList.toggle('show');
        }
    }
});
